class Solution:
    def countTriplets(self, nums):
        from collections import Counter
        pair = Counter()
        for a in nums:
            for b in nums:
                pair[a & b] += 1
        total = 0
        for c in nums:
            for v, freq in pair.items():
                if v & c == 0:
                    total += freq
        return total

