var countTriplets = function(nums) {
    const pair = new Map();
    for (const a of nums) {
        for (const b of nums) {
            const v = a & b;
            pair.set(v, (pair.get(v) || 0) + 1);
        }
    }
    let total = 0;
    for (const c of nums) {
        for (const [v, freq] of pair) {
            if ((v & c) === 0) total += freq;
        }
    }
    return total;
};
